esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.data_tree.size IS NOT NULL
// Peak data tree size per node in the time window
| STATS max_data_size = MAX(metrics.zookeeper.data_tree.size) BY host.name
// Alert when the in-memory data tree exceeds 1 GB (1,073,741,824 bytes)
// Unbounded growth causes memory pressure, GC pauses, and latency spikes
// Adjust based on available heap memory
| WHERE max_data_size > 1073741824
